   216→    private void putAndMaybeForward(final ThreadCache.DirtyEntry entry,
   217→                                    final InternalProcessorContext<?, ?> context) {
   218→        if (flushListener != null) {
   219→            final byte[] rawNewValue = entry.newValue();
   220→            final byte[] rawOldValue = rawNewValue == null || sendOldValues ? wrapped().get(entry.key()) : null;
   221→
   222→            // this is an optimization: if this key did not exist in underlying store and also not in the cache,
   223→            // we can skip flushing to downstream as well as writing to underlying store
   224→            if (rawNewValue != null || rawOldValue != null) {
   225→                // we need to get the old values if needed, and then put to store, and then flush
   226→                final ProcessorRecordContext current = context.recordContext();
   227→                try {
   228→                    context.setRecordContext(entry.entry().context());
   229→                    wrapped().put(entry.key(), entry.newValue());
   230→                    flushListener.apply(
   231→                        new Record<>(
   232→                            entry.key().get(),
   233→                            new Change<>(rawNewValue, sendOldValues ? rawOldValue : null),
   234→                            entry.entry().context().timestamp(),
   235→                            entry.entry().context().headers()));
   236→                } finally {
   237→                    context.setRecordContext(current);
   238→                }
   239→            }
   240→        } else {
   241→            final ProcessorRecordContext current = context.recordContext();
   242→            try {
   243→                context.setRecordContext(entry.entry().context());
   244→                wrapped().put(entry.key(), entry.newValue());
   245→            } finally {
   246→                context.setRecordContext(current);
   247→            }
   248→        }
   249→    }
