    @Override
    public long approximateNumEntries() {
        validateStoreOpen();
        lock.readLock().lock();
        try {
            validateStoreOpen();
            return wrapped().approximateNumEntries();
        } finally {
            lock.readLock().unlock();
        }
    }

    @Override
    public void commit(final Map<TopicPartition, Long> changelogOffsets) {
        validateStoreOpen();
        lock.writeLock().lock();
        try {
            validateStoreOpen();
            internalContext.cache().flush(cacheName);
            wrapped().commit(changelogOffsets);
        } finally {
            lock.writeLock().unlock();
        }
    }

    @Override
    public void flushCache() {
        validateStoreOpen();
        lock.writeLock().lock();
        try {
            validateStoreOpen();
            internalContext.cache().flush(cacheName);
        } finally {
            lock.writeLock().unlock();
        }
    }

    @Override
    public void clearCache() {
        validateStoreOpen();
        lock.writeLock().lock();
        try {
            validateStoreOpen();
            internalContext.cache().clear(cacheName);
        } finally {
            lock.writeLock().unlock();
        }
    }

    @Override
    public void close() {
        lock.writeLock().lock();
        try {
            final LinkedList<RuntimeException> suppressed = executeAll(
                () -> internalContext.cache().flush(cacheName),
                () -> internalContext.cache().close(cacheName),
                wrapped()::close
            );
            if (!suppressed.isEmpty()) {
                throwSuppressed("Caught an exception while closing caching key value store for store " + name(),
                    suppressed);
            }
        } finally {
            lock.writeLock().unlock();
        }
    }

    public enum CacheType {
        KEY_VALUE_STORE,
        TIMESTAMPED_KEY_VALUE_STORE,
        TIMESTAMPED_KEY_VALUE_STORE_WITH_HEADERS
    }
}

