    93→    public static class TopologyVersionListener {
    94→        final long topologyVersion; // the (minimum) version to wait for these threads to cross
    95→        final KafkaFutureImpl<Void> future; // the future waiting on all threads to be updated
    96→
    97→        public TopologyVersionListener(final long topologyVersion, final KafkaFutureImpl<Void> future) {
    98→            this.topologyVersion = topologyVersion;
    99→            this.future = future;
   100→        }
   101→    }
