   111→        this.config = config;
   112→        this.log = LoggerFactory.getLogger(getClass());
   113→        this.pausedTopologies = ConcurrentHashMap.newKeySet();
   114→
   115→        builders = new ConcurrentSkipListMap<>();
   116→        if (builder.hasNamedTopology()) {
