   238→    private void notifyLifecycleObservers() {
   239→        final long currentVersion = version.topologyVersion.get();
   240→        final Set<String> activeTopologies = namedTopologiesView();
   241→        for (final TopologyLifecycleObserver observer : lifecycleObservers) {
   242→            try {
   243→                observer.onTopologyChange(currentVersion, activeTopologies);
   244→            } catch (final Exception e) {
   245→                log.warn("Topology lifecycle observer threw exception", e);
   246→            }
   247→        }
   248→    }
