   263→    public void maybeWaitForNonEmptyTopology(final Supplier<StreamThread.State> threadState) {
   264→        if (isEmpty() && threadState.get().isAlive()) {
   265→            try {
   266→                lock();
   267→                while (isEmpty() && threadState.get().isAlive()) {
   268→                    try {
   269→                        log.debug("Detected that the topology is currently empty, waiting for something to process");
   270→                        version.topologyCV.await();
   271→                    } catch (final InterruptedException e) {
   272→                        log.error("StreamThread was interrupted while waiting on empty topology", e);
   273→                    }
   274→                }
   275→            } finally {
   276→                unlock();
   277→            }
   278→        }
   279→    }
