   627→    void addSubscribedTopicsFromMetadata(final Set<String> topics, final String logPrefix) {
   628→        applyToEachBuilder(b -> b.addSubscribedTopicsFromMetadata(topics, logPrefix));
   629→    }
   630→
   631→    void addSubscribedTopicsFromAssignment(final Set<TopicPartition> partitions, final String logPrefix) {
   632→        applyToEachBuilder(b -> b.addSubscribedTopicsFromAssignment(partitions, logPrefix));
   633→    }
   634→
   635→    public Collection<Set<String>> copartitionGroups() {
   636→        final List<Set<String>> copartitionGroups = new ArrayList<>();
   637→        applyToEachBuilder(b -> copartitionGroups.addAll(b.copartitionGroups()));
   638→        return copartitionGroups;
   639→    }
   640→
   641→    /**
   642→     * @return the {@link InternalTopologyBuilder} for this task's topology, guaranteed to be non-null
   643→     *
   644→     * @throws UnknownTopologyException  if the task is from a named topology that this client isn't aware of
   645→     */
   646→    private InternalTopologyBuilder lookupBuilderForTask(final TaskId task) {
   647→        final InternalTopologyBuilder builder = task.topologyName() == null ?
   648→            builders.get(UNNAMED_TOPOLOGY) :
   649→            builders.get(task.topologyName());
   650→        if (builder == null) {
   651→            throw new UnknownTopologyException("Unable to locate topology builder", task.topologyName());
   652→        } else {
   653→            return builder;
   654→        }
   655→    }
   656→
   657→    @SuppressWarnings("deprecation")
   658→    public Collection<NamedTopology> allNamedTopologies() {
   659→        return builders.values()
   660→            .stream()
   661→            .map(InternalTopologyBuilder::namedTopology)
   662→            .collect(Collectors.toSet());
   663→    }
   664→
   665→
   666→    /**
   667→     * @return the InternalTopologyBuilder for the NamedTopology with the given {@code topologyName}
   668→     *         or the builder for a regular Topology if {@code topologyName} is {@code null},
   669→     *         else returns {@code null} if {@code topologyName} is non-null but no such NamedTopology exists
   670→     */
   671→    public InternalTopologyBuilder lookupBuilderForNamedTopology(final String topologyName) {
   672→        return builders.get(getTopologyNameOrElseUnnamed(topologyName));
   673→    }
   674→
   675→    private boolean evaluateConditionIsTrueForAnyBuilders(final Function<InternalTopologyBuilder, Boolean> condition) {
   676→        for (final InternalTopologyBuilder builder : builders.values()) {
   677→            if (condition.apply(builder)) {
   678→                return true;
   679→            }
   680→        }
   681→        return false;
   682→    }
   683→
   684→    private void applyToEachBuilder(final Consumer<InternalTopologyBuilder> function) {
   685→        for (final InternalTopologyBuilder builder : builders.values()) {
   686→            function.accept(builder);
   687→        }
   688→    }
   689→
   690→    public static class Subtopology implements Comparable<Subtopology> {
   691→        final int nodeGroupId;
   692→        final String namedTopology;
   693→
   694→        public Subtopology(final int nodeGroupId, final String namedTopology) {
   695→            this.nodeGroupId = nodeGroupId;
   696→            this.namedTopology = namedTopology;
   697→        }
   698→
   699→        @Override
   700→        public boolean equals(final Object o) {
   701→            if (this == o) {
   702→                return true;
   703→            }
   704→            if (o == null || getClass() != o.getClass()) {
   705→                return false;
   706→            }
   707→            final Subtopology that = (Subtopology) o;
   708→            return nodeGroupId == that.nodeGroupId &&
   709→                    Objects.equals(namedTopology, that.namedTopology);
   710→        }
   711→
   712→        @Override
   713→        public int hashCode() {
   714→            return Objects.hash(nodeGroupId, namedTopology);
   715→        }
   716→
   717→        @Override
   718→        public int compareTo(final Subtopology other) {
   719→            if (nodeGroupId != other.nodeGroupId) {
   720→                return Integer.compare(nodeGroupId, other.nodeGroupId);
   721→            }
   722→            if (namedTopology == null) {
   723→                return other.namedTopology == null ? 0 : -1;
   724→            }
   725→            if (other.namedTopology == null) {
   726→                return 1;
   727→            }
   728→
   729→            // Both not null
   730→            return namedTopology.compareTo(other.namedTopology);
   731→        }
   732→    }
   733→}
