403→        // If there are named topologies but some are empty, this indicates a bug in user code
404→        if (hasNamedTopologies()) {
405→            if (hasNoLocalTopology()) {
406→                log.error("Detected a named topology with no input topics, a named topology may not be empty.");
407→                throw new TopologyException("Topology has no stream threads and no global threads, " +
408→                                                "must subscribe to at least one source topic or pattern.");
409→            }
410→        } else {
411→            // If both the global and non-global topologies are empty, this indicates a bug in user code
412→            if (hasNoLocalTopology() && !hasGlobalTopology()) {
413→                log.error("Topology with no input topics will create no stream threads and no global thread.");
414→                throw new TopologyException("Topology has no stream threads and no global threads, " +
415→                                                "must subscribe to at least one source topic or global table.");
416→            }
417→        }
418→
419→        // Lastly we check for an empty non-global topology and override the threads to zero if set otherwise
420→        if (configuredNumStreamThreads != 0 && hasNoLocalTopology()) {
421→            log.info("Overriding number of StreamThreads to zero for global-only topology");
422→            return 0;
423→        }
424→
425→        return configuredNumStreamThreads;
426→    }
427→
428→    /**
429→     * @return true iff the app is using named topologies, or was started up with no topology at all
430→     */
431→    public boolean hasNamedTopologies() {
432→        return !builders.containsKey(UNNAMED_TOPOLOGY);
433→    }
434→
435→    public Set<String> namedTopologiesView() {
436→        return hasNamedTopologies() ? Collections.unmodifiableSet(builders.keySet()) : emptySet();
437→    }
438→
439→    /**
440→     * @return true iff any of the topologies have a global topology
441→     */
442→    public boolean hasGlobalTopology() {
443→        return evaluateConditionIsTrueForAnyBuilders(InternalTopologyBuilder::hasGlobalStores);
444→    }
445→
446→    /**
447→     * @return true iff any of the topologies have no local (aka non-global) topology
448→     */
449→    public boolean hasNoLocalTopology() {
450→        return evaluateConditionIsTrueForAnyBuilders(InternalTopologyBuilder::hasNoLocalTopology);
451→    }
452→
453→    public boolean hasPersistentStores() {
454→        // If the app is using named topologies, there may not be any persistent state when it first starts up
455→        // but a new NamedTopology may introduce it later, so we must return true
456→        if (hasNamedTopologies()) {
457→            return true;
458→        }
459→        return evaluateConditionIsTrueForAnyBuilders(InternalTopologyBuilder::hasPersistentStores);
460→    }
461→
462→    public boolean hasStore(final String name) {
463→        return evaluateConditionIsTrueForAnyBuilders(b -> b.hasStore(name));
464→    }
465→
466→    public boolean hasOffsetResetOverrides() {
467→        // Return true if using named topologies, as there may be named topologies added later which do have overrides
468→        return hasNamedTopologies() || evaluateConditionIsTrueForAnyBuilders(InternalTopologyBuilder::hasOffsetResetOverrides);
469→    }
470→
471→    public Optional<AutoOffsetResetStrategy> offsetResetStrategy(final String topic) {
472→        for (final InternalTopologyBuilder builder : builders.values()) {
473→            if (builder.containsTopic(topic)) {
474→                return Optional.ofNullable(builder.offsetResetStrategy(topic));
475→            }
476→        }
477→        log.warn("Unable to look up offset reset strategy for topic {} " +
478→            "as this topic does not appear in the sources of any of the current topologies: {}\n " +
479→                "This may be due to natural race condition when removing a topology but it should not " +
480→                "persist or appear frequently.",
481→            topic, namedTopologiesView()
482→        );
483→        // returning `null` for an Optional return type triggers spotbugs
484→        // we added an exception for NP_OPTIONAL_RETURN_NULL for this method
485→        // when we remove NamedTopologies, we can remove this exception
486→        return null;
487→    }
488→
489→
490→    public Collection<String> fullSourceTopicNamesForTopology(final String topologyName) {
491→        Objects.requireNonNull(topologyName, "topology name must not be null");
492→        return lookupBuilderForNamedTopology(topologyName).fullSourceTopicNames();
493→    }
494→
495→    public Collection<String> allFullSourceTopicNames() {
496→        final List<String> sourceTopics = new ArrayList<>();
497→        applyToEachBuilder(b -> sourceTopics.addAll(b.fullSourceTopicNames()));
498→        return sourceTopics;
499→    }
500→
501→    Pattern sourceTopicPattern() {
502→        final StringBuilder patternBuilder = new StringBuilder();
503→
504→        applyToEachBuilder(b -> {
505→            final String patternString = b.sourceTopicPatternString();
506→            if (!patternString.isEmpty()) {
507→                patternBuilder.append(patternString).append("|");
508→            }
509→        });
510→
511→        if (patternBuilder.length() > 0) {
512→            patternBuilder.setLength(patternBuilder.length() - 1);
513→            return Pattern.compile(patternBuilder.toString());
514→        } else {
515→            return EMPTY_ZERO_LENGTH_PATTERN;
516→        }
517→    }
518→
519→    public boolean usesPatternSubscription() {
520→        return evaluateConditionIsTrueForAnyBuilders(InternalTopologyBuilder::usesPatternSubscription);
521→    }
522→
523→    // Can be empty if app is started up with no Named Topologies, in order to add them on later
524→    public boolean isEmpty() {
525→        return builders.isEmpty();
526→    }
527→
528→    public String topologyDescriptionString() {
529→        if (isEmpty()) {
530→            return "";
531→        }
532→        final StringBuilder sb = new StringBuilder();
533→
534→        applyToEachBuilder(b -> sb.append(b.describe().toString()));
535→
536→        return sb.toString();
537→    }
538→
539→    /**
540→     * @return the {@link ProcessorTopology subtopology} built for this task, guaranteed to be non-null
541→     *
542→     * @throws UnknownTopologyException  if the task is from a named topology that this client isn't aware of
543→     */
544→    public ProcessorTopology buildSubtopology(final TaskId task) {
545→        final InternalTopologyBuilder builder = lookupBuilderForTask(task);
546→        return builder.buildSubtopology(task.subtopology());
547→    }
548→
549→    public ProcessorTopology globalTaskTopology() {
550→        if (hasNamedTopologies()) {
551→            throw new IllegalStateException("Global state stores are not supported with Named Topologies");
552→        }
553→        return globalTopology;
554→    }
555→
556→    public Map<String, StateStore> globalStateStores() {
557→        return globalStateStores;
558→    }
559→
560→    public Map<String, List<String>> stateStoreNameToSourceTopicsForTopology(final String topologyName) {
561→        return lookupBuilderForNamedTopology(topologyName).stateStoreNameToFullSourceTopicNames();
562→    }
563→
564→    public Set<String> stateStoreNamesForSubtopology(final String topologyName, final int subtopologyId) {
565→        return lookupBuilderForNamedTopology(topologyName).stateStoreNamesForSubtopology(subtopologyId);
566→    }
567→
568→    public Map<String, List<String>> stateStoreNameToSourceTopics() {
569→        final Map<String, List<String>> stateStoreNameToSourceTopics = new HashMap<>();
570→        applyToEachBuilder(b -> stateStoreNameToSourceTopics.putAll(b.stateStoreNameToFullSourceTopicNames()));
571→        return stateStoreNameToSourceTopics;
572→    }
573→
574→    public String storeForChangelogTopic(final String topicName) {
575→        for (final InternalTopologyBuilder builder : builders.values()) {
576→            final String store = builder.storeForChangelogTopic(topicName);
577→            if (store != null) {
578→                return store;
579→            }
580→        }
581→        log.warn("Unable to locate any store for topic {}", topicName);
582→        return "";
583→    }
584→
585→    /**
586→     * @param storeName       the name of the state store
587→     * @param topologyName    the name of the topology to search for stores within
588→     * @return topics subscribed from source processors that are connected to these state stores
589→     */
590→    public Collection<String> sourceTopicsForStore(final String storeName, final String topologyName) {
591→        return lookupBuilderForNamedTopology(topologyName).sourceTopicsForStore(storeName);
592→    }
593→
594→    public static String getTopologyNameOrElseUnnamed(final String topologyName) {
595→        return topologyName == null ? UNNAMED_TOPOLOGY : topologyName;
596→    }
597→
598→    /**
599→     * @param topologiesToExclude the names of any topologies to exclude from the returned topic groups,
600→     *                            eg because they have missing source topics and can't be processed yet
601→     *
602→     * @return                    flattened map of all subtopologies (from all topologies) to topics info
603→     */
604→    public Map<Subtopology, TopicsInfo> subtopologyTopicsInfoMapExcluding(final Set<String> topologiesToExclude) {
605→        final Map<Subtopology, TopicsInfo> subtopologyTopicsInfo = new HashMap<>();
606→        applyToEachBuilder(b -> {
607→            if (!topologiesToExclude.contains(b.topologyName())) {
608→                subtopologyTopicsInfo.putAll(b.subtopologyToTopicsInfo());
609→            }
610→        });
611→        return subtopologyTopicsInfo;
612→    }
613→
614→    /**
615→     * @return    map from topology to its subtopologies and their topics info
616→     */
617→    public Map<String, Map<Subtopology, TopicsInfo>> topologyToSubtopologyTopicsInfoMap() {
618→        final Map<String, Map<Subtopology, TopicsInfo>> topologyToSubtopologyTopicsInfoMap = new HashMap<>();
619→        applyToEachBuilder(b -> topologyToSubtopologyTopicsInfoMap.put(b.topologyName(), b.subtopologyToTopicsInfo()));
620→        return  topologyToSubtopologyTopicsInfoMap;
621→    }
622→
623→    public Map<String, List<String>> nodeToSourceTopics(final TaskId task) {
624→        return lookupBuilderForTask(task).nodeToSourceTopics();
625→    }
626→
627→    void addSubscribedTopicsFromMetadata(final Set<String> topics, final String logPrefix) {
628→        applyToEachBuilder(b -> b.addSubscribedTopicsFromMetadata(topics, logPrefix));
629→    }
630→
631→    void addSubscribedTopicsFromAssignment(final Set<TopicPartition> partitions, final String logPrefix) {
632→        applyToEachBuilder(b -> b.addSubscribedTopicsFromAssignment(partitions, logPrefix));
633→    }
634→
635→    public Collection<Set<String>> copartitionGroups() {
636→        final List<Set<String>> copartitionGroups = new ArrayList<>();
637→        applyToEachBuilder(b -> copartitionGroups.addAll(b.copartitionGroups()));
638→        return copartitionGroups;
639→    }
640→
641→    /**
642→     * @return the {@link InternalTopologyBuilder} for this task's topology, guaranteed to be non-null
643→     *
644→     * @throws UnknownTopologyException  if the task is from a named topology that this client isn't aware of
645→     */
646→    private InternalTopologyBuilder lookupBuilderForTask(final TaskId task) {
647→        final InternalTopologyBuilder builder = task.topologyName() == null ?
648→            builders.get(UNNAMED_TOPOLOGY) :
649→            builders.get(task.topologyName());
650→        if (builder == null) {
651→            throw new UnknownTopologyException("Unable to locate topology builder", task.topologyName());
652→        } else {
653→            return builder;
654→        }
655→    }
656→
657→    @SuppressWarnings("deprecation")
658→    public Collection<NamedTopology> allNamedTopologies() {
659→        return builders.values()
660→            .stream()
661→            .map(InternalTopologyBuilder::namedTopology)
662→            .collect(Collectors.toSet());
663→    }
664→
665→
666→    /**
667→     * @return the InternalTopologyBuilder for the NamedTopology with the given {@code topologyName}
668→     *         or the builder for a regular Topology if {@code topologyName} is {@code null},
669→     *         else returns {@code null} if {@code topologyName} is non-null but no such NamedTopology exists
670→     */
671→    public InternalTopologyBuilder lookupBuilderForNamedTopology(final String topologyName) {
672→        return builders.get(getTopologyNameOrElseUnnamed(topologyName));
673→    }
674→
675→    private boolean evaluateConditionIsTrueForAnyBuilders(final Function<InternalTopologyBuilder, Boolean> condition) {
676→        for (final InternalTopologyBuilder builder : builders.values()) {
677→            if (condition.apply(builder)) {
678→                return true;
679→            }
680→        }
681→        return false;
682→    }
683→
684→    private void applyToEachBuilder(final Consumer<InternalTopologyBuilder> function) {
685→        for (final InternalTopologyBuilder builder : builders.values()) {
686→            function.accept(builder);
687→        }
688→    }
689→
690→    public static class Subtopology implements Comparable<Subtopology> {
691→        final int nodeGroupId;
692→        final String namedTopology;
693→
694→        public Subtopology(final int nodeGroupId, final String namedTopology) {
695→            this.nodeGroupId = nodeGroupId;
696→            this.namedTopology = namedTopology;
697→        }
698→
699→        @Override
700→        public boolean equals(final Object o) {
701→            if (this == o) {
702→                return true;
703→            }
704→            if (o == null || getClass() != o.getClass()) {
705→                return false;
706→            }
707→            final Subtopology that = (Subtopology) o;
708→            return nodeGroupId == that.nodeGroupId &&
709→                    Objects.equals(namedTopology, that.namedTopology);
710→        }
711→
712→        @Override
713→        public int hashCode() {
714→            return Objects.hash(nodeGroupId, namedTopology);
715→        }
716→
717→        @Override
718→        public int compareTo(final Subtopology other) {
719→            if (nodeGroupId != other.nodeGroupId) {
720→                return Integer.compare(nodeGroupId, other.nodeGroupId);
721→            }
722→            if (namedTopology == null) {
723→                return other.namedTopology == null ? 0 : -1;
724→            }
725→            if (other.namedTopology == null) {
726→                return 1;
727→            }
728→
729→            // Both not null
730→            return namedTopology.compareTo(other.namedTopology);
731→        }
732→    }
733→}
