    17→package org.apache.kafka.streams.state.internals;
    18→
    19→import org.apache.kafka.clients.consumer.ConsumerRecord;
    20→import org.apache.kafka.common.TopicPartition;
    21→import org.apache.kafka.common.serialization.Serializer;
    22→import org.apache.kafka.common.utils.Bytes;
    23→import org.apache.kafka.streams.KeyValue;
    24→import org.apache.kafka.streams.StreamsConfig;
    25→import org.apache.kafka.streams.processor.StateStore;
    26→import org.apache.kafka.streams.processor.StateStoreContext;
    27→import org.apache.kafka.streams.processor.internals.ChangelogRecordDeserializationHelper;
    28→import org.apache.kafka.streams.processor.internals.RecordBatchingStateRestoreCallback;
    29→import org.apache.kafka.streams.query.Position;
    30→import org.apache.kafka.streams.query.PositionBound;
    31→import org.apache.kafka.streams.query.Query;
    32→import org.apache.kafka.streams.query.QueryConfig;
    33→import org.apache.kafka.streams.query.QueryResult;
    34→import org.apache.kafka.streams.state.KeyValueIterator;
    35→import org.apache.kafka.streams.state.KeyValueStore;
    36→
    37→import org.slf4j.Logger;
    38→import org.slf4j.LoggerFactory;
    39→
    40→import java.util.Iterator;
    41→import java.util.List;
    42→import java.util.Map;
    43→import java.util.NavigableMap;
    44→import java.util.NoSuchElementException;
    45→import java.util.Set;
    46→import java.util.TreeMap;
    47→import java.util.TreeSet;
    48→
    49→import static org.apache.kafka.streams.StreamsConfig.InternalConfig.IQ_CONSISTENCY_OFFSET_VECTOR_ENABLED;
    50→
    51→public class InMemoryKeyValueStore implements KeyValueStore<Bytes, byte[]> {
    52→
    53→    private static final Logger LOG = LoggerFactory.getLogger(InMemoryKeyValueStore.class);
    54→
    55→    private final String name;
    56→    private final NavigableMap<Bytes, byte[]> map = new TreeMap<>();
    57→    private final Position position = Position.emptyPosition();
    58→    private volatile boolean open = false;
    59→    private StateStoreContext context;
    60→
    61→    public InMemoryKeyValueStore(final String name) {
    62→        this.name = name;
    63→    }
    64→
    65→    @Override
    66→    public String name() {
    67→        return name;
    68→    }
    69→
    70→    @Override
    71→    public void init(final StateStoreContext stateStoreContext,
    72→                     final StateStore root) {
    73→        if (root != null) {
    74→            final boolean consistencyEnabled = StreamsConfig.InternalConfig.getBoolean(
    75→                stateStoreContext.appConfigs(),
    76→                IQ_CONSISTENCY_OFFSET_VECTOR_ENABLED,
    77→                false
    78→            );
    79→            // register the store
    80→            open = true;
    81→
    82→            stateStoreContext.register(
    83→                root,
    84→                (RecordBatchingStateRestoreCallback) records -> {
    85→                    synchronized (position) {
    86→                        for (final ConsumerRecord<byte[], byte[]> record : records) {
    87→                            put(Bytes.wrap(record.key()), record.value());
    88→                            ChangelogRecordDeserializationHelper.applyChecksAndUpdatePosition(
    89→                                record,
    90→                                consistencyEnabled,
    91→                                position
    92→                            );
    93→                        }
    94→                    }
    95→                }
    96→            );
    97→        }
    98→
    99→        open = true;
   100→        this.context = stateStoreContext;
   101→    }
   102→
   103→    @Override
   104→    public boolean persistent() {
   105→        return false;
   106→    }
   107→
   108→    @Override
   109→    public boolean isOpen() {
   110→        return open;
   111→    }
   112→
   113→    @Override
   114→    public Position getPosition() {
   115→        return position;
   116→    }
   117→
   118→    @Override
   119→    public <R> QueryResult<R> query(final Query<R> query,
   120→                                    final PositionBound positionBound,
   121→                                    final QueryConfig config) {
   122→
   123→        return StoreQueryUtils.handleBasicQueries(
   124→            query,
   125→            positionBound,
   126→            config,
   127→            this,
   128→            position,
   129→            context
   130→        );
   131→    }
   132→
   133→    @Override
   134→    public synchronized byte[] get(final Bytes key) {
   135→        return map.get(key);
   136→    }
   137→
   138→    @Override
   139→    public synchronized void put(final Bytes key, final byte[] value) {
   140→        putInternal(key, value);
   141→    }
   142→
   143→    @Override
   144→    public synchronized byte[] putIfAbsent(final Bytes key, final byte[] value) {
   145→        final byte[] originalValue = get(key);
   146→        if (originalValue == null) {
   147→            put(key, value);
   148→        }
   149→        return originalValue;
   150→    }
   151→
   152→    // the unlocked implementation of put method, to avoid multiple lock/unlock cost in `putAll` method
   153→    private void putInternal(final Bytes key, final byte[] value) {
   154→        synchronized (position) {
   155→            if (value == null) {
   156→                map.remove(key);
   157→            } else {
   158→                map.put(key, value);
   159→            }
   160→
   161→            StoreQueryUtils.updatePosition(position, context);
   162→        }
   163→    }
   164→
   165→    @Override
   166→    public synchronized void putAll(final List<KeyValue<Bytes, byte[]>> entries) {
   167→        for (final KeyValue<Bytes, byte[]> entry : entries) {
   168→            putInternal(entry.key, entry.value);
   169→        }
   170→    }
   171→
   172→    @Override
   173→    public synchronized <PS extends Serializer<P>, P> KeyValueIterator<Bytes, byte[]> prefixScan(final P prefix, final PS prefixKeySerializer) {
   174→
   175→        final Bytes from = Bytes.wrap(prefixKeySerializer.serialize(null, prefix));
   176→        final Bytes to = Bytes.increment(from);
   177→
   178→        return new InMemoryKeyValueIterator(map.subMap(from, true, to, false).keySet(), true);
   179→    }
   180→
   181→    @Override
   182→    public synchronized byte[] delete(final Bytes key) {
   183→        return map.remove(key);
   184→    }
   185→
   186→    @Override
   187→    public synchronized KeyValueIterator<Bytes, byte[]> range(final Bytes from, final Bytes to) {
   188→        return range(from, to, true);
   189→    }
   190→
   191→    @Override
   192→    public synchronized KeyValueIterator<Bytes, byte[]> reverseRange(final Bytes from, final Bytes to) {
   193→        return range(from, to, false);
   194→    }
   195→
   196→    private KeyValueIterator<Bytes, byte[]> range(final Bytes from, final Bytes to, final boolean forward) {
   197→        if (from == null && to == null) {
   198→            return getKeyValueIterator(map.keySet(), forward);
   199→        } else if (from == null) {
   200→            return getKeyValueIterator(map.headMap(to, true).keySet(), forward);
   201→        } else if (to == null) {
   202→            return getKeyValueIterator(map.tailMap(from, true).keySet(), forward);
   203→        } else if (from.compareTo(to) > 0) {
   204→            LOG.warn("Returning empty iterator for fetch with invalid key range: from > to. " +
   205→                    "This may be due to range arguments set in the wrong order, " +
   206→                    "or serdes that don't preserve ordering when lexicographically comparing the serialized bytes. " +
   207→                    "Note that the built-in numerical serdes do not follow this for negative numbers");
   208→            return KeyValueIterators.emptyIterator();
   209→        } else {
   210→            return getKeyValueIterator(map.subMap(from, true, to, true).keySet(), forward);
   211→        }
   212→    }
   213→
   214→    private KeyValueIterator<Bytes, byte[]> getKeyValueIterator(final Set<Bytes> rangeSet, final boolean forward) {
   215→        return new InMemoryKeyValueIterator(rangeSet, forward);
   216→    }
   217→
   218→    @Override
   219→    public synchronized KeyValueIterator<Bytes, byte[]> all() {
   220→        return range(null, null);
   221→    }
   222→
   223→    @Override
   224→    public synchronized KeyValueIterator<Bytes, byte[]> reverseAll() {
   225→        return new InMemoryKeyValueIterator(map.keySet(), false);
   226→    }
   227→
   228→    @Override
   229→    public long approximateNumEntries() {
   230→        return map.size();
   231→    }
   232→
   233→    @Override
   234→    public void commit(final Map<TopicPartition, Long> changelogOffsets) {
   235→        // do-nothing since it is in-memory
   236→    }
   237→
   238→    @Override
   239→    public void close() {
   240→        map.clear();
   241→        open = false;
   242→    }
   243→
   244→    private class InMemoryKeyValueIterator implements KeyValueIterator<Bytes, byte[]> {
   245→        private final Iterator<Bytes> iter;
   246→        private Bytes currentKey;
   247→        private Boolean iteratorOpen = true;
   248→
   249→        private InMemoryKeyValueIterator(final Set<Bytes> keySet, final boolean forward) {
   250→            if (forward) {
   251→                this.iter = new TreeSet<>(keySet).iterator();
   252→            } else {
   253→                this.iter = new TreeSet<>(keySet).descendingIterator();
   254→            }
   255→        }
   256→
   257→        @Override
   258→        public boolean hasNext() {
   259→            if (!iteratorOpen) {
   260→                throw new IllegalStateException(String.format("Iterator for store %s has already been closed.", name));
   261→            }
   262→            if (currentKey != null) {
   263→                if (map.containsKey(currentKey)) {
   264→                    return true;
   265→                } else {
   266→                    currentKey = null;
   267→                    return hasNext();
   268→                }
   269→            }
   270→            if (!iter.hasNext()) {
   271→                return false;
   272→            }
   273→            currentKey = iter.next();
   274→            return hasNext();
   275→        }
   276→
   277→        @Override
   278→        public KeyValue<Bytes, byte[]> next() {
   279→            if (!hasNext()) {
   280→                throw new NoSuchElementException();
   281→            }
   282→            final KeyValue<Bytes, byte[]> ret = new KeyValue<>(currentKey, map.get(currentKey));
   283→            currentKey = null;
   284→            return ret;
   285→        }
   286→
   287→        @Override
   288→        public void close() {
   289→            iteratorOpen = false;
   290→        }
   291→
   292→        @Override
   293→        public Bytes peekNextKey() {
   294→            if (!hasNext()) {
   295→                throw new NoSuchElementException();
   296→            }
   297→            return currentKey;
   298→        }
   299→    }
   300→}
