    29→/**
    30→ * A representation of a position vector with respect to a set of topic partitions. For example, in
    31→ * Interactive Query ({@link org.apache.kafka.streams.KafkaStreams#query(StateQueryRequest)}, a
    32→ * query result may contain information from multiple store partitions, each of which contains
    33→ * information from multiple input topics' partitions. This class can be used to summarize all of
    34→ * that positional information.
    35→ * <p>
    36→ * This class is threadsafe, although it is mutable. Readers are recommended to use {@link
    37→ * Position#copy()} to avoid seeing mutations to the Position after they get the reference. For
    38→ * examples, when a store executes a {@link org.apache.kafka.streams.processor.StateStore#query(Query,
    39→ * PositionBound, QueryConfig)} request and returns its current position via {@link
    40→ * QueryResult#setPosition(Position)}, it should pass a copy of its position instead of the mutable
    41→ * reference.
    42→ */
    43→@Evolving
    44→public class Position {
    45→
    46→    private final ConcurrentHashMap<String, ConcurrentHashMap<Integer, Long>> position;
    47→
    48→    private Position(final ConcurrentHashMap<String, ConcurrentHashMap<Integer, Long>> position) {
    49→        this.position = position;
    50→    }
    51→
    52→    /**
    53→     * Create a new, empty Position.
    54→     */
    55→    public static Position emptyPosition() {
    56→        return new Position(new ConcurrentHashMap<>());
    57→    }
    58→
    59→    /**
    60→     * Create a new Position and populate it with a mapping of topic -&gt; partition -&gt; offset.
    61→     * <p>
    62→     * Note, the resulting Position does not share any structure with the provided map, so
    63→     * subsequent changes to the map or Position will not affect the other.
    64→     */
    65→    public static Position fromMap(final Map<String, ? extends Map<Integer, Long>> map) {
    66→        return new Position(deepCopy(map));
    67→    }
    68→
    69→    /**
    70→     * Augment an existing Position by setting a new offset for a topic and partition.
    71→     * <p>
    72→     * Note: enforces monotonicity on offsets. I.e., if there is already a component for the same
    73→     * topic and partition with a larger offset, the update will succeed but not overwrite the
    74→     * offset.
    75→     * <p>
    76→     * Returns a self-reference for chained calls. Note: this method mutates the Position.
    77→     */
    78→    public Position withComponent(final String topic, final int partition, final long offset) {
    79→        position
    80→            .computeIfAbsent(topic, k -> new ConcurrentHashMap<>())
    81→            .compute(
    82→                partition,
    83→                (integer, prior) -> prior == null || offset > prior ? offset : prior
    84→            );
    85→        return this;
    86→    }
    87→
    88→    /**
    89→     * Create a deep copy of the Position.
    90→     */
    91→    public Position copy() {
