import org.apache.kafka.common.utils.Bytes;
import org.apache.kafka.streams.KeyValue;
import org.apache.kafka.test.InternalMockProcessorContext;

import java.util.ArrayList;
import java.util.List;

/**
 * Fray test for InMemoryKeyValueStore deadlock.
 *
 * Before the fix, the restore callback acquired position → this, while
 * put() acquired this → position, causing a deadlock under concurrent access.
 */
public class InMemoryKeyValueStoreDeadlockTest {

    public static void main(final String[] args) throws Exception {
        final InternalMockProcessorContext<Void, Void> context = new InternalMockProcessorContext<>();
        final InMemoryKeyValueStore store = new InMemoryKeyValueStore("test-store");
        store.init(context, store);

        // Prepare restore entries
        final List<KeyValue<byte[], byte[]>> restoreEntries = new ArrayList<>();
        for (int i = 0; i < 5; i++) {
            restoreEntries.add(new KeyValue<>(
                ("restore-key-" + i).getBytes(),
                ("restore-value-" + i).getBytes()
            ));
        }

        // Thread 1: restore operations (before fix: position → this; after fix: this → position)
        final Thread restorer = new Thread(() -> {
            context.restore(store.name(), restoreEntries);
        });

        restorer.start();

        // Main thread: normal put operations (acquires this → position)
        for (int i = 0; i < 5; i++) {
            store.put(
                new Bytes(("key-" + i).getBytes()),
                ("value-" + i).getBytes()
            );
        }

        restorer.join();
    }
}

